import dotenv from "dotenv-flow";
dotenv.config();
import { z } from "zod";

export const envSchema = z.object({
  DATABASE_URL: z.url()
});

export type Env = z.infer<typeof envSchema>;

const result = envSchema.safeParse(process.env);

if (!result.success) {
  console.error("❌ Invalid environment configuration");
  console.error(z.prettifyError(result.error));
  process.exit(1);
}

export const env: Readonly<Env> = Object.freeze(result.data);

export default env;

import mongoose from "mongoose";
import { env } from "./env";

if (!env.DATABASE_URL) {
  throw new Error("Please provide DATABASE_URL in the environment variables");
}

export const connectDB = async (): Promise<void> => {
  try {
    const conn = await mongoose.connect(env.DATABASE_URL as string);
    console.log(`MongoDB Connected: ${conn.connection.host}`);
  } catch (error) {
    console.error("MongoDB Connection Failed:", error);
    process.exit(1);
  }
};

import { Connection } from "mongoose";

declare global {
  var mongooseCache:
    | {
        conn: Connection | null;
        promise: Promise<Connection> | null;
      }
    | undefined;
}

export {};

import mongoose, { Connection } from "mongoose";

const MONGODB_URI = process.env.DATABASE_URL!;

if (!MONGODB_URI) {
  throw new Error("Missing MONGODB_URI environment variable");
}

const globalCache = global.mongooseCache ?? {
  conn: null,
  promise: null
};

global.mongooseCache = globalCache;

export async function dbConnect(): Promise<Connection> {
  if (globalCache.conn) {
    return globalCache.conn;
  }

  if (!globalCache.promise) {
    globalCache.promise = mongoose.connect(MONGODB_URI).then(m => m.connection);
  }

  try {
    globalCache.conn = await globalCache.promise;
  } catch (error) {
    console.error("❌ Error connecting to MongoDB:", error);
    globalCache.promise = null;
    throw error;
  }

  console.log("✅ MongoDB connected");
  return globalCache.conn;
}
